        cache_policy_weak: ['Il cache a lungo termine è debole su risorse interne campionate', 'Diverse risorse interne campionate non dichiarano una policy cache durevole.', 'Applica header cache forti agli asset versionati e mantieni policy brevi solo per contenuti volutamente mutabili.'],
        blocking_markup_structure: ['Script sincroni e stylesheet pesano ancora sull’avvio', 'La struttura HTML grezza suggerisce ancora pressione evitabile all’avvio prima delle sonde lab profonde.', 'Riduci il fan-out nell’head, differisci script non critici e tieni nel percorso di avvio solo il CSS del primo viewport.'],
        field_data_unavailable: ['Nessun dato field confermato per questo target', 'PerfAtlas non ha confermato un dataset CrUX utilizzabile per questo target pubblico.', 'Aggiungi una chiave CrUX/Google o rilancia quando il target ha abbastanza traffico pubblico misurabile.'],
        field_lcp_poor: ['Largest Contentful Paint lento nei dati field', 'I dati real-user mostrano un LCP p75 sopra la soglia consigliata.', 'Ottimizza percorso dell’elemento LCP, risposta server, risorse bloccanti e media hero.'],
        field_inp_poor: ['Interazione lenta nei dati field', 'I dati real-user mostrano un INP p75 sopra la soglia consigliata.', 'Riduci task lunghi, hydration costosa, script terzi e JavaScript critico.'],
        field_cls_poor: ['I layout shift sono troppo alti', 'I dati field indicano instabilità visiva percepibile dagli utenti.', 'Riserva dimensioni, stabilizza componenti tardivi ed evita inserimenti di contenuto sopra il viewport.'],
        lab_lcp_slow: ['LCP lento nei run lab', 'Il run lab rappresentativo mostra un Largest Contentful Paint lento.', 'Ottimizza l’elemento LCP, riduci CSS/JS bloccanti, comprimi media hero e accorcia la risposta server.'],
        lab_main_thread_heavy: ['Il main-thread blocca troppo nei run lab', 'Il run lab mostra troppo lavoro bloccante sul thread principale.', 'Differisci script non critici, riduci hydration, spezza task lunghi e sposta lavoro costoso fuori dal percorso critico.'],
        lab_payload_bloat: ['Payload totale e numero richieste sono alti', 'Il run lab rappresentativo carica troppi byte o troppe richieste.', 'Riduci peso JS e media, consolida risorse e rimuovi terze parti o duplicati a basso valore.'],
        lab_server_response_slow: ['Il tempo risposta server rallenta il percorso critico', 'Backend o edge ritardano materialmente l’inizio del render.', 'Riduci latenza origin, migliora cache e ottimizza lavoro server sulle route critiche.'],
        render_blocking_resources: ['Risorse bloccanti ritardano ancora l’avvio', 'Il render critico è ritardato da stylesheet o script bloccanti.', 'Inlinea o separa CSS critico, differisci script non essenziali e precarica solo risorse che sbloccano il primo paint.'],
        unused_javascript_lab: ['JavaScript inutilizzato pesa ancora sulla route rappresentativa', 'Il run lab mostra ancora molto JavaScript consegnato ma non usato su questa route.', 'Spezza i bundle in modo più aggressivo, differisci codice non critico e rimuovi script terzi a basso valore.'],
        unused_css_lab: ['CSS inutilizzato gonfia ancora il percorso critico di render', 'Il run rappresentativo consegna CSS non necessario per questa route.', 'Pulisci CSS inutilizzato, separa gli stili per route quando ha senso e tieni solo il CSS first-screen nel percorso di avvio.'],
        offscreen_images_lab: ['Immagini offscreen competono ancora con il render critico', 'La route rappresentativa spende ancora banda su immagini non necessarie al primo viewport.', 'Lazy-load immagini offscreen, servi varianti responsive più precise e riserva eager loading ai media del primo viewport.'],
        third_party_lab_summary: ['Il codice di terze parti costa ancora troppo sulla route rappresentativa', 'Il run lab attribuisce una quota significativa di lavoro o byte a risorse di terze parti.', 'Ritarda o rimuovi terze parti a basso valore e tieni le dipendenze inevitabili fuori dal percorso critico.'],
        lab_cache_ttl_opportunity: ['La route rappresentativa ha ancora un’opportunità di cache TTL', 'Il run lab vede ancora risorse che potrebbero dichiarare una durata cache più forte.', 'Rafforza la policy cache delle risorse versionate e verifica gli header pubblici finali dopo il deploy.'],
        lab_text_compression_opportunity: ['La route rappresentativa ha ancora un’opportunità di compressione testo', 'Il run lab vede ancora risorse testo comprimibili troppo costose sulla rete.', 'Attiva compressione testo coerente sul percorso pubblico finale e verifica gli header produzione.'],
        document_ttfb_slow: ['Il tempo risposta documento è lento sulle pagine campionate', 'Diverse pagine campionate mostrano un avvio risposta lento prima che il render possa iniziare.', 'Profila latenza origin, metti in cache i percorsi caldi e rendi le route critiche compatibili edge quando possibile.'],
        html_document_heavy: ['Il payload HTML è pesante sulle pagine campionate', 'La risposta HTML iniziale porta molto markup o payload inline prima ancora delle sotto-risorse.', 'Riduci markup server, sposta dati inline grandi fuori dall’HTML quando sicuro e lascia inline solo risorse critiche.'],
        document_compression_missing: ['I documenti HTML non sono compressi in modo coerente', 'Alcuni documenti HTML campionati sono trasferiti senza un chiaro segnale di compressione testo.', 'Attiva compressione sulle risposte HTML produzione e verifica il percorso pubblico finale.'],
        static_assets_uncacheable: ['Alcune risorse statiche sono esplicitamente non cacheabili', 'Risorse statiche interne tornano con direttive che impediscono riuso efficiente.', 'Separa policy HTML mutabili e risorse versionate per rendere cacheabili i file immutabili.'],
